"use client";

import { FormEvent, useState } from "react";
import { useRouter } from "next/navigation";
import { signInWithEmailAndPassword } from "firebase/auth";
import { getFirebaseClientAuth } from "@/lib/firebase/client";

function writeAuthCookies(input: { userId: string; email?: string | null; token: string }) {
  const workspaceId = process.env.NEXT_PUBLIC_DEFAULT_WORKSPACE_ID || "default";
  const maxAge = 60 * 60 * 8;
  document.cookie = `tk_auth_token=${encodeURIComponent(input.token)}; Path=/; Max-Age=${maxAge}; SameSite=Lax`;
  document.cookie = `tk_user_id=${encodeURIComponent(input.userId)}; Path=/; Max-Age=${maxAge}; SameSite=Lax`;
  document.cookie = `tk_workspace_id=${encodeURIComponent(workspaceId)}; Path=/; Max-Age=${maxAge}; SameSite=Lax`;
  document.cookie = `tk_email=${encodeURIComponent(input.email || "")}; Path=/; Max-Age=${maxAge}; SameSite=Lax`;
}

export function SignInForm() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const credentials = await signInWithEmailAndPassword(getFirebaseClientAuth(), email, password);
      const token = await credentials.user.getIdToken();

      writeAuthCookies({
        userId: credentials.user.uid,
        email: credentials.user.email,
        token,
      });

      router.replace("/dashboard");
      router.refresh();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Falha ao autenticar.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-4 rounded-lg border bg-white p-6">
      <h1 className="text-xl font-semibold">Entrar</h1>
      <div className="space-y-1">
        <label className="text-sm font-medium" htmlFor="email">Email</label>
        <input id="email" type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full rounded border px-3 py-2" required />
      </div>
      <div className="space-y-1">
        <label className="text-sm font-medium" htmlFor="password">Senha</label>
        <input id="password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full rounded border px-3 py-2" required />
      </div>
      {error ? <p className="text-sm text-red-600">{error}</p> : null}
      <button type="submit" disabled={loading} className="w-full rounded bg-black px-4 py-2 text-white disabled:opacity-70">
        {loading ? "Entrando..." : "Entrar"}
      </button>
    </form>
  );
}
